Go 基础 02 — 条件语句 if/switch

原文：xyf1111.github.io/go-study-02/

if

if的条件里不需要括号

func bounded(v int) int {
        if v &gt; 100 {
            return 100
        } else if v &lt; 0 {
            return 0
        } else {
            return v
        }
    }

if的条件里可以赋值

if contents, err := ioutil.ReadFile(filename); err != nil {
		fmt.Println(err)
	} else {
		fmt.Printf(&quot;%s\n&quot;, contents)
	}

if条件里赋值的变量作用域就在这个if语句里

switch

switch会自动break，除非使用fallthrough

func eval(a, b int, op string) int {
	var result int
	switch op {
	case &quot;+&quot;:
		result = a + b
	case &quot;-&quot;:
		result = a - b
	case &quot;*&quot;:
		result = a * b
	case &quot;/&quot;:
		result = a / b
	default:
		panic(&quot;unsupported operator:&quot; + op)
	}
	return result
}

switch后可以没有表达式

func grade(score int) string {
	g := &quot;&quot;
	switch  {
	case score &lt; 60:
		g = &quot;D&quot;
	case score &lt; 80:
		g = &quot;C&quot;
	case score &lt; 90:
		g = &quot;B&quot;
	case score &lt;= 100:
		g = &quot;A&quot;
	default:
		panic(fmt.Sprintf(&quot;Wrong score: %d&quot;, score))
	}
	return g
}
案例
if/else分支
if和else分支结构在Go中当然是直接了当的了
func branchSample1()  {
	if 7 % 2 == 0 {
		//7是偶数
		fmt.Println(&quot;7 is even&quot;)
	} else {
		//7是奇数
		fmt.Println(&quot;7 is odd&quot;)
	}
	//也可以不要else，只用if
	if 8 % 4 == 0 {
		fmt.Println(&quot;8 is divisible by 4&quot;)
	}
	//在条件语句之前可以有一个语句，任何在这里声明的变量都可以在所有的条件分支中使用
	if num := 9; num &lt; 0 {
		fmt.Println(num, &quot;is negative&quot;)
	} else if num &lt; 10 {
		fmt.Println(num, &quot;has 1 digit&quot;)
	} else {
		fmt.Println(num, &quot;has multiple digit&quot;)
	}
}
switch分支
func branchSample2()  {
	//一个基本的switch
	i := 2
	switch i {
	case 1:
		fmt.Println(&quot;one&quot;)
	case 2:
		fmt.Println(&quot;two&quot;)
	case 3:
		fmt.Println(&quot;three&quot;)
	}
	//在一个case语句中可以使用逗号分割多个表达式
	//使用了可选的default分支
	switch time.Now().Weekday() {
	case time.Saturday, time.Sunday:
		fmt.Println(&quot;It&#039;s the weekend&quot;)
	default:
		fmt.Println(&quot;It&#039;s a weekday&quot;)
	}
	//不带表达式的switch是实现if/else的另一种方式
	//这里展示了case表达式是如何使用非常量的
	t := time.Now()
	switch  {
	case t.Hour() &lt; 12:
		fmt.Println(&quot;it&#039;s before noon&quot;)
	default:
		fmt.Println(&quot;it&#039;s after noon&quot;)
	}
}

