获取元素：map[key]
name := m[&quot;name&quot;]
key不存在时，获得Value类型的初始值
name1 := m[&quot;name1&quot;]
用value, ok := map[key]来判断是否存在key
if name1, ok := m[&quot;name1&quot;]; ok {
		fmt.Println(name1)
	} else {
