Go 基础 05 — 字符串与字符处理

原文：xyf1111.github.io/go-study-05/

寻找最长不含有重复字符的子串

abcabcbb -&gt; abc
bbbbb -&gt; b
pwwkew -&gt;wke

func lenthofNonRepeatingSubStr(s string) int {
	lastOccurred := make(map[rune]int)
	start := 0
	maxLength := 0
	for i, ch := range []rune (s){
		if lastI, ok := lastOccurred[ch]; ok &amp;&amp; lastI &gt;= start {
			fmt.Println(lastI)
			fmt.Println(ok)
			start = lastI + 1
		}
		if i-start+1 &gt; maxLength {
			maxLength = i-start+1
		}
		lastOccurred[ch] = i
	}
	return maxLength
}

