案例1
统计一个文本文件的字符个数
package main

import (
	&quot;bufio&quot;
	&quot;fmt&quot;
	&quot;io&quot;
	&quot;os&quot;
)
//定义一个结构体保存统计结果
type charCount struct {
	//英文个数
	chCount		int
	//空格个数
	spaceCount	int
	//数字个数
	numCount	int
	//其他个数
	otherCount	int
}

func main() {
	/**
	思路：打开一个文件，创建一个Reader
	每读取一行，统计字符保存到结构体中
	 */
	file, err := os.Open(&quot;fileOperations/abc.txt&quot;)
	if err != nil {
		fmt.Println(&quot;file open err:&quot;, err)
	}
	reader := bufio.NewReader(file)
	fileC := charCount{}
	//循环读取file内容
	for {
		s, err := reader.ReadString(&#039;\n&#039;)
		//为了兼容中文转化为rune
		for _, r := range []rune(s) {
			switch {
			case r &gt;= &#039;a&#039; &amp;&amp; r &lt;= &#039;z&#039;:
				fallthrough
			case r &gt;= &#039;A&#039; &amp;&amp; r &lt;= &#039;Z&#039;:
				fileC.chCount++
			case r &gt; &#039;0&#039; &amp;&amp; r &lt; &#039;9&#039;:
				fileC.numCount++
			case r == &#039; &#039; || r == &#039;\t&#039;:
				fileC.spaceCount++
			default:
				fileC.otherCount++
			}
		}
		if err == io.EOF {
			break
		}
	}

	fmt.Printf(&quot;file has chcount: %d, numcount: %d, spaceCount: %d, otherCount: %d&quot;, fileC.chCount, fileC.numCount, fileC.spaceCount, fileC.otherCount)
}
将数据序列化成json字符串
将数据(结构体，Map，Slice，基础数据类型)序列化成json字符串
json序列化是指将有key-value结构的数据类型(比如：结构体，Map，Slice)序列化成json字符串的操作
package main

import (
	&quot;encoding/json&quot;
