Go Instance 04

原文：xyf1111.github.io/go-instance-04/

goroutine和channel
goroutine和channel协同工作
具体要求

开启一个writeData协程，向管道intChan中写入50个整数
开启一个readData协程，从管道intChan中读取writeData写入的数据
注意writeData和readData操作的是同一个管道
主线程需要等待writeData和readData协程都完成工作才能退出管道

思路分析

思路分析
package main

import &quot;fmt&quot;

func writeData(intChan chan int)  {
	for i := 1; i &lt;= 50; i++ {
		intChan &lt;-i
		fmt.Println(&quot;write:&quot;, i)
	}
	close(intChan)
}

func readData(intChan chan int, exitChan chan bool)  {
	for {
		n, ok := &lt;-intChan
		if !ok {
			break
		}
		fmt.Println(&quot;read:&quot;, n)
	}
	exitChan &lt;- true
	close(exitChan)
}

func main() {
	intChan := make(chan int, 50)
	exitChan := make(chan bool, 1)

	go writeData(intChan)
	go readData(intChan, exitChan)

	for {
		_, ok := &lt;-exitChan
		if !ok {
			break
		}
	}
}
读和写频率不一样也没有问题
package main

import (
	&quot;fmt&quot;
	&quot;time&quot;
)

func writeData(intChan chan int)  {
	for i := 0; i &lt; 50; i++ {
		intChan &lt;- i
		fmt.Println(&quot;write:&quot;, i)
	}
	close(intChan)
}

func readData(intChan chan int, exitChan chan bool) {
	for {
		v, ok := &lt;-intChan
		if !ok {
			break
		}
		time.Sleep(time.Second)
		fmt.Println(&quot;read:&quot;, v)
	}
	exitChan &lt;- true
	close(exitChan)
}

func main() {
	intChan := make(chan int, 10)
	exitChan := make(chan bool, 1)

	go writeData(intChan)
	go readData(intChan, exitChan)
	for {
		if _, ok := &lt;-exitChan; !ok{
			break
		}
	}
}
注意：如果只向管道写入数据而没有读取，就会造成堵塞而deadlock

