时间
Go对时间和时间段提供了大量的支持
package main

import (
	&quot;fmt&quot;
	&quot;time&quot;
)

func main() {
	p := fmt.Println

	//获得当前时间
	now := time.Now()
	p(now)

	//提供年月日等信息，可以构建一个time。时间总是关联位置信息，例如时区
	then := time.Date(2009, 11, 17, 20, 34, 58, 651387237, time.UTC)
	p(then)

	//提取出时间的各个组成部分
	p(then.Year())
	p(then.Month())
	p(then.Day())
	p(then.Hour())
	p(then.Minute())
	p(then.Second())
	p(then.Nanosecond())
	p(then.Location())

	//输出时间的星期
	p(then.Weekday())

	//使用方法比较时间，精确到秒
	p(then.Before(now))
	p(then.After(now))
	p(then.Equal(now))

	//Sub返回一个duration来表示两个时间点的间隔时间
	diff := now.Sub(then)
	p(diff)

	//计算不同单位下的时间长度值
	p(diff.Hours())
	p(diff.Minutes())
	p(diff.Seconds())
	p(diff.Nanoseconds())

	//可以使用Add将时间后移一个时间间隔，或在时间间隔前加-，将时间前移一个时间间隔
	p(then.Add(diff))
	p(then.Add(-diff))
}
