package main

import (
	&quot;fmt&quot;
	&quot;time&quot;
)

func main() {
	//分别使用带Unix或者UnixNano的time.Now来获取从自协调世界时起到现在的秒数或纳秒数
	now := time.Now()
	secs := now.Unix()
	nanos := now.UnixNano()
