)

func main() {
	//这个URL实例，包含一个Scheme，认证信息，主机名，端口，路径，查询参数和片段
	s := &quot;postgres://user:pass@host.com:5432/path#f&quot;

	//解析URL，确保解析没错
	u, e := url.Parse(s)
