以上只是参考，不能保证切换，不能保证在其他地方不切换

案例
协程
Go协程在执行上来说是轻量级的线程
package main

import &quot;fmt&quot;

func f(s string)  {
	for i := 0; i &lt; 3; i++ {
		fmt.Println(s)
	}
}
//Go协程在执行上来说是轻量级的线程
func main() {
	//使用一般方式运行f函数
	f(&quot;direct&quot;)
	//使用go f(s)在一个Go协程中调用这个函数
	//这个新的Go协程会并行的执行这个函数的调用
	go f(&quot;gorouting&quot;)
	//为匿名函数启动一个Go协程
	go func(msg string) {
		for i := 0; i &lt; 10; i++ {
			fmt.Println(msg)
		}
	}(&quot;going&quot;)
	//现在这两个Go协程在独立的Go协程中异步运行，所以需要等他们结束
	//Scanln代码，我们在程序退出前按下任意键结束
	var in string
	fmt.Scanln(&amp;in)
	fmt.Println(&quot;done&quot;)
}
当运行这个程序时，将先看见阻塞式调用，然后是两个go协程交替输出，这种交替输出表示Go运行时是以异步方式运行协程的

golang/并发/go-并发-02-—-channel.content:
Go 并发 02 — channel使用

原文：xyf1111.github.io/go-study-15/

channel
channel
buffered channel(带缓冲区的channel)
range(关闭channel)
理论基础Communication Sequential Process(CSP)
案例
channel(通道)
通道是连接多个Go协程的管道，可以从一个Go协程将值发送到通道，然后在别的Go协程中接收
package main

import (
	&quot;fmt&quot;
)

func channel1() {
	//使用make(chan val-type)创建一个新的通道
	//通道类型就是传递值的类型
	message := make(chan string)

	//使用 channel &lt;- 语法发送一个新的值到通道中
	go func() {
		message &lt;- &quot;ping&quot;
	}()

	fmt.Println(message)

	//使用 &lt;- channel 语法从通道中获取一个值
	msg := &lt;- message

	fmt.Println(msg)
}

func main() {
	channel1()
}
运行程序时，通过通道，消息“ping”成功的从一个Go协程传到另一个。默认发送和接收操作是阻塞的，直到发送方和接收方都准备完毕。这个特性允许不使用任何其他的同步操作，可以在程序结尾等待消息“ping”
通道缓冲
默认通道是无缓冲的，这意味着只有在对应的接收(&lt;-chan)通道准备好接收时才允许发送(chan&lt;-)。可缓冲通道允许在没有接收方的情况下，缓存限定数量的值
package main

import (
	&quot;fmt&quot;
)

func channel2()  {
	//这里make了一个通道，最多允许缓存2个值
	message := make(chan string, 2)

	//因为这个通道有缓冲区，即使没有一个对应的并发接收方，也可以继续发送
	message &lt;- &quot;buffered&quot;
	message &lt;- &quot;channel&quot;
	//接收时，也可以接收两个值
	fmt.Println(&lt;-message)
	fmt.Println(&lt;-message)
}

func main() {
	channel2()
}
通道同步
可以使用通道来同步Go协程间的执行状态。这里使用阻塞的接收方式来等待一个Go协程的运行结束
package main

import (
	&quot;fmt&quot;
	&quot;time&quot;
)

func channel3() {
	//创建一个缓存为1的bool类型通道
	done := make(chan bool, 1)
	//运行一个worker Go协程，并给予用于通知的通道
	go worker(done)
	//程序将在接收到通道中worker发出的通知前一直阻塞
	&lt;-done
}

//这是一个我们将要在 Go 协程中运行的函数。
// done 通道将被用于通知其他 Go 协程这个函数已经工作完毕
func worker(done chan bool)  {
	fmt.Println(&quot;working...&quot;)
	time.Sleep(time.Second)
	fmt.Println(&quot;done&quot;)
	//发送一个值来通知完工啦。
	done &lt;- true
}

func main() {
	channel3()
}
如果将done &lt;- true这行代码从程序中移除，程序甚至会在worker还没开始运行就结束
通道方向
当使用通道作为函数参数时，可以指定通道是不是只用来接收或发送值。这个特性提升了程序的类型安全性
package main

import (
	&quot;fmt&quot;
)

func channel4() {
	pings := make(chan string, 1)
	pongs := make(chan string, 1)
	ping(pings, &quot;message&quot;)
	pong(pings, pongs)
	fmt.Println(&lt;-pongs)
}

//ping函数定义一个只允许发送数据的通道
//尝试使用这个函数来接收数据会得到一个编译时错误
func ping(pings chan&lt;- string, str string) {
	pings &lt;- str
}
//pong函数允许通道pings接收函数，通道pongs发送函数
func pong(pings &lt;-chan string, pongs chan&lt;- string) {
	msg := &lt;-pings
	pongs &lt;- msg
}

func main() {
	channel4()
}
通道选择器
Go的通道选择器可以同时等待多个通道操作。Go协程和通道以及选择器的结合是Go的一个强大特性
package main

import (
	&quot;fmt&quot;
	&quot;time&quot;
)

func main() {
	//创建2个通道，从这两个选择
	c1 := make(chan string, 1)
	c2 := make(chan string, 1)

	//c1通道在1秒后接收值，这个模拟Go协程中阻塞的RPC操作
	go func() {
		time.Sleep(time.Second)
		c1 &lt;- &quot;one&quot;
	}()

	//c2通道在2秒后接收值
	go func() {
		time.Sleep(time.Second * 2)
		c2 &lt;- &quot;two&quot;
	}()

	//使用select关键字来同时等待这两个值，并打印各自的值
	for i :=0; i &lt; 2; i++ {
		select {
		case msg := &lt;-c1:
			fmt.Println(msg)
		case msg := &lt;-c2:
			fmt.Println(msg)
		}
	}
}
注意两个协程并发运行，程序总共仅运行2秒左右
超时处理
超时对于一个连接外部资源，或者其他一些需要花费执行时间操作的程序而言是很重要的。得益于通道和select，在Go中实现超时操作是简洁而优雅的
package main

import (
	&quot;fmt&quot;
	&quot;time&quot;
)

func main() {
	//在这个例子中，执行一个外部调用，在2秒后通过通道c1返回执行结果
	c1 := make(chan string, 1)
	go func() {
		time.Sleep(time.Second * 2)
		c1 &lt;- &quot;result 1&quot;
	}()

	//使用select实现超时操作
	//result := &lt;-c1等待结果，&lt;-Time.After等待超时1秒后发送的值
	//由于select默认处理第一个已准备好的接收操作，如果这个操作超过允许的1秒的话，将会执行超时case
	select {
	case result := &lt;- c1:
		fmt.Println(result)
	case &lt;-time.After(time.Second * 1):
		fmt.Println(&quot;result1 超时&quot;)
	}

	//执行一个外部调用，2秒后通过通道c2返回执行结果
	c2 := make(chan string, 1)
	go func() {
		time.Sleep(time.Second * 2)
		c2 &lt;- &quot;result 2&quot;
	}()

	//将超时延长至3秒，如果操作小于3秒将执行result输出case
	select {
	case result := &lt;-c2:
		fmt.Println(result)
	case &lt;-time.After(time.Second * 3):
		fmt.Println(&quot;result2超时&quot;)
	}
}
运行程序，首先显示运行超时的操作，然后是成功接收的。使用select超时方式需要使用通道传递结果。这对于一般情况是个好方式，因为其他重要的Go特性是基于通道和select的
非阻塞式通道操作
常规的通过通道发送和接收数据是阻塞的。然而，可以使用带default子句select来实现非阻塞的发送、接收，甚至是非阻塞的多路select
package main

import &quot;fmt&quot;
//这是一个非阻塞接收的例子
func main() {
	message := make(chan string, 1)
	signal := make(chan string, 1)

	//如果message有值存在，select将值传到msg中
	//如果不存在直接执行default
	select {
	case msg := &lt;-message:
		fmt.Println(&quot;received message:&quot;, msg)
	default:
		fmt.Println(&quot;no message receives&quot;)
	}

	//这个非阻塞方法，如果msg成功向message传值，执行case
	//否则执行default
	msg := &quot;hi&quot;
	select {
	case message &lt;- msg:
		fmt.Println(&quot;sent message:&quot;, msg)
	default:
		fmt.Println(&quot;no message sent&quot;)
	}

	signal &lt;- &quot;world&quot;
	//可以在default前使用多个case子句实现一个多路的非阻塞的选择器
	//这里尝试在message和signal上同时使用非阻塞的接收操作
	//如果case1和case2都满足，随机执行case1或case2
	select {
	case msg := &lt;-message:
		fmt.Println(&quot;receives message:&quot;, msg)
	case sign := &lt;-signal:
		fmt.Println(&quot;receives signal:&quot;, sign)
	default:
		fmt.Println(&quot;no activity&quot;)
	}
}
通道的关闭
关闭一个通道意味着不能再向这个通道发送值了。这个特性可以用来给这个通道接收方传达工作已经完成的消息
package main

import &quot;fmt&quot;

func main() {
	//在这个例子中，将使用一个jobs通道来传递main()中Go协程任务执行的结果信息到一个工作Go协程中
	//当没有多余任务给这个工作Go协程时，可以close这个jobs通道
	job := make(chan int, 5)
	done := make(chan bool, 1)

	//这是工作Go协程，使用j, more := &lt;-job循环从job接收数据
	//在接收的这个特殊的二值形式的值中，如果job已经关闭，并且通道中的所有值都已经接收完毕
	//那么more的值将是false。当完成所有任务时，将使用这个特性通过done通道去进行通知
	go func() {
		for {
			j, more := &lt;-job
			if more {
				fmt.Println(&quot;received job:&quot;, j)
			} else {
				fmt.Println(&quot;received all jobs&quot;)
				done &lt;- true
				return
			}
		}
	}()

	//这里使用job发送3个任务到工作函数中，然后关闭job
	for i := 1; i &lt;= 3; i++ {
		job &lt;- i
		fmt.Println(&quot;sent job:&quot;, i)
	}

	close(job)
	fmt.Println(&quot;sent all job&quot;)

	//使用通道同步方法等待任务结束
	&lt;-done
}
通道遍历
可以使用range语法来遍历从通道中取得的值。一个非空通道是可以关闭的，但是通道中的值仍然可以被接收到
package main

import &quot;fmt&quot;

func main() {
	//遍历在queue通道中的两个值
	queue := make(chan string, 2)

	queue &lt;- &quot;one&quot;
	queue &lt;- &quot;two&quot;

	close(queue)

	//这个range迭代从queue中得到的每个值
	//因为close了通道，这个通道会在接收完第二个值后结束
	//如果没有close，那么这个循环将继续阻塞执行，等待接收第三个值
	for elem := range queue {
		fmt.Println(elem)
	}
}

golang/并发/go-并发-03-—-select机制.content:
Go 并发 03 — select多路复用

原文：xyf1111.github.io/go-study17/

select语句介绍
Go语言中的select语句用于监控并选择一组case语句执行相应的代码。它看起来类似于switch语句，但是select语句中所有case中的表达式必须是channel的发送或者接受操作。一个典型的select的使用示例如下：
select {
case &lt;- ch1:
    fmt.Println(&quot;liwenzhou.com&quot;)
case ch2 &lt;- 1:
    fmt.Println(&quot;qimi&quot;)
}
Go语言中select关键字也能够让当前goroutine同时等待ch1的可读和ch2的可写，在ch1和ch2状态改变之前，select会一直堵塞下去，直到其中的一个channel转为就绪状态时执行对应的case分支的代码。如果多个channel同时就绪的话则随机选择一个case执行。
处理上面展示的典型实例外，接下来我们逐一介绍一些select的特殊示例
空select
空select指的是内部不包含任何case，例如：
select {

}
空的select语句会直接堵塞当前的goroutine，使得该goroutine进入无法唤醒的永久休眠状态
只有一个case
如果select中只包含一个case，那么该select就变成了一个堵塞的channel读/写操作。
select {
case &lt;- ch1:
    fmt.Println(&quot;liwenzhou.com&quot;)
}
上面的代码，当ch1可读时会执行打印操作，否则就会堵塞
有default语句
如果select中还可以包含default语句，用于当其他case都不满足时执行一些默认操作。
select {
case &lt;- ch1:
    fmt.Println(&quot;liwenzhou.com&quot;)
default:
    time.Sleep(time.Second)
}
上面的代码，当ch1可读时会执行打印操作，否则就执行default语句中的代码，这里就相当于做了一个非堵塞的channel读取操作。
总结

select不存在任何的case：永久堵塞当前goroutine
select只存在一个case：堵塞的发送/接收
select存在多个case：随机选择一个满足条件的case执行
select存在default，其他case都不满足时，执行default语句中的代码

如何在select中实现优先级
已知，当select存在多个case时会随机选择一个满足条件的case执行
现在我们有一个需求：我们有一个函数会持续不间断地从ch1和ch2中分别接收任务1和任务2，如何确保当ch1和ch2同时达到就绪状态时，优先执行任务1，在没有任务1的时候再去执行任务2
func worker (ch1, ch2 &lt;-chan int, stopCh chan struct{}) {
    for {
        select {
        case &lt;-stopCh:
            return
        case job1 := &lt;-ch1:
            fmt.Println(job1)
        default:
            select {
            case job2 := &lt;-ch2:
                fmt.Println(job2)
            default:
            }
        }
    }
}
上面的代码通过嵌套两个select实现了”优先级”，看起来是满足题目要求的。但是这代码有点问题，如果ch1和ch2都没有达到就绪状态的话，整个程序不会堵塞而是进入死循环。
func worker2(ch1, ch2 &lt;-chan int, stopCh chan struct{}) {
    for {
        select {
        case &lt;-stopCh:
            return
        case job1 := ch1:
            fmt.Printl(job1)
        case job2 := ch2:
        priority:
            for {
                select {
                case job1 := &lt;-ch1:
                    fmt.Println(job1)
                default:
                    break priority
                }
            }
            fmt.Println(job2)
        }
    }
}
这一次不仅使用了嵌套的select，还组合使用了for循环和LABEL来实现题目的要求。上面的代码在外层select选中执行job := &lt;-ch2时，进入到内层select循环尝试执行job1 := &lt;-ch1，当ch1就绪时就会一直执行，否则跳出内层select
实际应用场景
K8s的controller中就有关于上面这个技巧的实际使用示例，这里在关于select中实现优先级相关代码的关键处都已添加了注释。
// kubernetes/pkg/controller/nodelifecycle/scheduler/taint_manager.go
func (tc *NoExecuteTaintManager) worker(worker int, done func(), stopCh &lt;-chan struct{}) {
	defer done()

	// 当处理具体事件的时候，我们会希望 Node 的更新操作优先于 Pod 的更新
	// 因为 NodeUpdates 与 NoExecuteTaintManager无关应该尽快处理
	// -- 我们不希望用户(或系统)等到PodUpdate队列被耗尽后，才开始从受污染的Node中清除pod。
	for {
		select {
		case &lt;-stopCh:
			return
		case nodeUpdate := &lt;-tc.nodeUpdateChannels[worker]:
			tc.handleNodeUpdate(nodeUpdate)
			tc.nodeUpdateQueue.Done(nodeUpdate)
		case podUpdate := &lt;-tc.podUpdateChannels[worker]:
			// 如果我们发现了一个 Pod 需要更新，我么你需要先清空 Node 队列.
		priority:
			for {
				select {
				case nodeUpdate := &lt;-tc.nodeUpdateChannels[worker]:
					tc.handleNodeUpdate(nodeUpdate)
					tc.nodeUpdateQueue.Done(nodeUpdate)
				default:
					break priority
				}
			}
			// 在 Node 队列清空后我们再处理 podUpdate.
			tc.handlePodUpdate(podUpdate)
			tc.podUpdateQueue.Done(podUpdate)
		}
	}
}

golang/底层原理/go-slice.content:
Go Slice

原文：xyf1111.github.io/go-slice/

数组在Go语言中没那么常用，更常用的数据结构是切片，即动态数组，其长度并不固定，我们可以向切片中追加元素，它会在容量不足时自动扩容。
在Go语言中，切片类型的声明方式和数组有一些相似，不过由于切片的长度是动态的，所以声明时只需要指定切片中的元素类型
[]int
[]interface{}
从切片的定义我们能推测出，切片在编译期间生成的类型会包含切片中的元素类型，即int或者interface()等。cmd/compile/internal/type.NewSlice就是编译期间用于创建切片类型的函数
func NewSlice(elem *Type) *Type {
    if t := elem.Cache.slice; t != nil {
        if t.Elem() != elem {
            Fatalf(&quot;elem mismatch&quot;)
        }
        return t
    }

    t := New(TSLICE)
    t.Extra = Slice{
        Elem: elem,
    }
    elem.Cache.slice = t
    return t
}
上述方法返回结构体重的Extra字段是一个只包含切片内元素类型的结构，也就是说切片内元素的类型都是在编译期间确定的，编译器确定了类型之后，会将类型存储在Extra字段中帮助程序在运行时动态获取。
数据结构
编译期间的切片是cmd/compile/internal/type.Slice类型的，但是在运行时切片可以由如下reflect.SliceHeader结构体表示，其中

Data 是指向数组的指针
Len 是当前切片的长度
Cap 是当前切片的容量，即Data数组的大小

type SliceHeader struct {
    Data    uintptr
    Len     int
    Cap     int
}
Data是一片连续的内存空间，这片内存空间可以用于存储切片中的全部元素，数组中的元素只是逻辑上的概念，底层存储其实都是连续的，所以我们可以将切片理解成一片连续的内存空间加上长度和容量的标识

Go语言切片结构体
从上图中，我们会发现切片和数组的关系非常密切，切片引入了一个抽象层，提供了对数组中部分连续片段的引用，而作为数组的引用，我们可以在运行区间修改它的长度和范围。当切片底层的数组长度不足时就会触发扩容，切片指向的数组可能会发生变化，不过在上层看来切片是没有变化的，上层只需要与切片打交道不需要关心数组的变化
编译器在编译期间简化了获取数组大小、读写数组中的元素等操作：因为数组的内存固定且连续，多数操作都会直接读写内存的特定位置。但是切片是运行时才会确定内容的结构，所有操作还需要依赖Go语言的运行时。
初始化
Go语言包含三种初始化切片的方式

通过下标的方式获得数组或者切片的一部分
使用字面量初始化新的切片
使用关键字make创建切片

arr[0:3] or slice[0:3]
slice := []int{1, 2, 3}
slice := make([]int, 10)
使用下标
使用下标创建切片是最原始也最接近汇编语言的方式，它是所有方法中最为底层的一种，编译器会将arr[0:3]或者slice[0:3]等语句转换成OpSliceMake操作，可以通过下面代码来验证
package opslicemake

func newSlice() []int {
    arr := [3]int{1, 2, 3}
    slice := arr[0:1]
    return slice
}
通过GOSSAFUNC变量编译上述代码可以得到一系列SSA中间代码，其中slice := arr[0:1]语句在”decompose builtin”阶段对应的代码如下所示
v27 (+5) = SliceMake &lt;[]int&gt; v11 v14 v17

name &amp;arr[*[3]int]: v11
name slice.ptr[*int]: v11
name slice.len[int]: v14
name slice.cap[int]: v17
SliceMake操作会接受四个参数创建新的切片，元素类型、数组指针、切片大小和容量，这也是我们在数据结构一节中提到的切片的几个字段，需要注意的是使用下标初始化切片不会拷贝原数组或者切片中的数据，它只会创建一个指向原数组的切片结构体，所以修改新切片的数据也会修改原切片
字面量
当使用字面量[]int{1, 2, 3}创建新的切片时，cmd/compile/internal/gc.slicelit函数会在编译期间将它展开成如下所示的代码片段
var vstat [3]int
vstat[0] = 1
vstat[1] = 2
vstat[2] = 3
var vauto *[3]int = new([3]int)
*vauto = vstat
slice := vauto[:]

根绝切片中的元素数量对底层数据的大小进行推断并创建一个数组
将这些字面量元素存储到初始化的数组中
创建一个同样指向[3]int类型的数组指针
将静态存储区的数组vstat赋值给vauto指针所在的地址
通过[:]操作获取一个底层使用vauto的切片

第五步中的[:]就是使用下标创建切片的方法，从这一点我们也能看出[:]操作切片最底层的一种方法
关键字
如果使用字面量的方式创建切片，大部分工作都会在编译期间完成。但是当我们使用make关键字创建切片时，很多工作都需要运行时参与；调用方必须向make函数传入切片的大小以及可选的容量，类型检查期间的cmd/compile/internal/gc.typecheck1函数会校验入参
func typecheck1(n *Node, top int) (res *Node) {
	switch n.Op {
	...
	case OMAKE:
		args := n.List.Slice()

		i := 1
		switch t.Etype {
		case TSLICE:
			if i &gt;= len(args) {
				yyerror(&quot;missing len argument to make(%v)&quot;, t)
				return n
			}

			l = args[i]
			i++
			var r *Node
			if i &lt; len(args) {
				r = args[i]
			}
			...
			if Isconst(l, CTINT) &amp;&amp; r != nil &amp;&amp; Isconst(r, CTINT) &amp;&amp; l.Val().U.(*Mpint).Cmp(r.Val().U.(*Mpint)) &gt; 0 {
				yyerror(&quot;len larger than cap in make(%v)&quot;, t)
				return n
			}

			n.Left = l
			n.Right = r
			n.Op = OMAKESLICE
		}
	...
	}
}
上面的函数不仅会检查len是否传入，还会保证传入的容量cap一定大于或者等于len。除了校验参数之外，当前函数会将OMAKE节点转换成OMAKESLICE，中间代码生成的cmd/compile/internal/gc.walkexpr函数会依据下面两个条件转换OMAKESLICE类型的节点：

切片的大小和容量是否足够小
切片是否发生了逃逸，最终在堆上初始化

当切片发生逃逸或者非常大时，运行时需要runtime.makeslice在堆上初始化切片，如果当前的切片不会发生逃逸并且切片非常小的时候，make([]int, 3, 4)会被直接转换成如下所示的代码：
var arr [4]int
n := arr[:3]
上述代码会初始化数组并通过下标[:3]得到数组对应的切片，这两部分都会在编译阶段完成，编译器会在栈上或者静态存储区创建数组并将[:3]转换成上一节提到的OpSliceMake操作
分析了主要由编译器处理的分支后，我们回到用于创建切片时的运行时函数runtime.makeslice，这个函数的实现很简单：
func makeslice(et *_type, len, cap int) unsafe.Pointer {
	mem, overflow := math.MulUintptr(et.size, uintptr(cap))
	if overflow || mem &gt; maxAlloc || len &lt; 0 || len &gt; cap {
		mem, overflow := math.MulUintptr(et.size, uintptr(len))
		if overflow || mem &gt; maxAlloc || len &lt; 0 {
			panicmakeslicelen()
		}
		panicmakeslicecap()
	}

	return mallocgc(mem, et, true)
}
上述函数的主要工作是计算切片占用的内存空间并在堆上申请一片连续的内存，它使用如下的方式计算占用的内存
内存空间=切片中元素大小×切片容量
虽然编译期间可以检查出很多错误，但是在创建切片的过程中如果发生了以下错误会直接出发运行时错误并崩溃：

内存空间的大小发生了溢出
申请的内存大于最大可支配的内存
传入的长度小于0或者长度大于容量

runtime.makeslice在最后调用的runtime.mallocgc是用于申请内存的函数，这个函数的实现还是比较复杂的，如果遇到了比较小的对象会直接初始化在Go语言调度器里面的P结构中，而大于32KB的对象会在堆上初始化。
在之前版本的Go语言中，数组指针、长度和容量会被合成一个runtime.slice结构，但是从cmd/compile:move slice construction to callers of makeslice提交之后，构建结构体reflect.SliceHeader的工作就交给了runtime.makeslice的调用方，该函数仅会返回指向底层数组的指针，调用方会在编译期间构建切片结构体：
func typecheck1(n *Node, top int) (res *Node) {
	switch n.Op {
	...
	case OSLICEHEADER:
	switch
		t := n.Type
		n.Left = typecheck(n.Left, ctxExpr)
		l := typecheck(n.List.First(), ctxExpr)
		c := typecheck(n.List.Second(), ctxExpr)
		l = defaultlit(l, types.Types[TINT])
		c = defaultlit(c, types.Types[TINT])

		n.List.SetFirst(l)
		n.List.SetSecond(c)
	...
	}
}
OSLICEHEADER操作会创建reflect.SliceHeader结构体，其中包含切片的长度和容量，它是切片在运行时的表示：
type SliceHeader struct {
    Data    uintptr
    Len     int
    Cap     int
}
正是因为大多数对切片类型的操作并不需要直接操作原来的runtime.slice结构体，所以reflect.SliceHeader的引入能够减少切片初始化时的少量开销，该改动不仅能够减少0.2%的Go语言包大小，还能够减少92个runtime.panicIndex的调用，占Go语言二进制的3.5%
访问元素
使用len和cap获取长度或者容量是切片最常见的操作，编译器将它们看成两种特殊操作，即OLEN和OCAP，cmd/compile/internal/gc.state.expr函数会在SSA生成阶段将它们分别转换成OpSliceLen和OpSliceCap
func (s *state) expr(n *Node) *ssa.Value {
	switch n.Op {
	case OLEN, OCAP:
		switch {
		case n.Left.Type.IsSlice():
			op := ssa.OpSliceLen
			if n.Op == OCAP {
				op = ssa.OpSliceCap
			}
			return s.newValue1(op, types.Types[TINT], s.expr(n.Left))
		...
		}
	...
	}
}
访问切片中的字段可能会触发”decompose builtin”阶段的优化，len(slice)或者cap(slice)在一些情况下会直接替换成切片的长度或者容量，不需要在运行时获取
(SlicePtr (SliceMake ptr _ _ )) -&gt; ptr
(SliceLen (SliceMake _ len _)) -&gt; len
(SliceCap (SliceMake _ _ cap)) -&gt; cap
除了直接获取切片的长度和容量之外，访问切片中元素使用OINDEX操作也会在中间代码生成期间转换成对地址的直接访问
func (s *state) expr(n *Node) *ssa.Value {
	switch n.Op {
	case OINDEX:
		switch {
		case n.Left.Type.IsSlice():
			p := s.addr(n, false)
			return s.load(n.Left.Type.Elem(), p)
		...
		}
	...
	}
}
切片的操作基本都是在编译期间完成的，除了访问切片的长度、容量或者其中的元素之外，编译期间也会将包含range关键字的遍历转换成形式更简单的循环
追加和扩容
使用append关键字向切片中追加元素也是常见的切片操作，中间代码生成阶段的cmd/compile/internal/gc.state.append方法会根据返回值是否会覆盖原变量，选择进入两种流程，如果append返回的新切片不需要赋值回原有的变量，就会进入如下的处理流程：
// append(slice, 1, 2, 3)
ptr, len, cap := slice
newlen := len + 3
if newlen &gt; cap {
    ptr, len, cap = growslice(slice, newlen)
    newlen = len + 3
}
*(ptr+len) = 1
*(ptr+len+1) = 2
*(ptr+len+2) = 3
return makeslice(ptr, newlen, cap)
我们会先解构切片结构体获取它的数组指针、大小和容量，如果在追加元素后切片的大小大于容量，那么就会调用runtime.growslice对切片进行扩容并将新的元素依次加入切片。
如果使用slice = append(slice, 1, 2, 3)语句，那么 append 后的切片会覆盖原切片，这时cmd/compile/internal/gc.state.append方法会使用另一种方式展开关键字：
// slice = append(slice, 1, 2, 3)
a := &amp;slice
ptr, len, cap := slice
newlen := len + 3
if uint(newlen) &gt; uint(cap) {
   newptr, len, newcap = growslice(slice, newlen)
   vardef(a)
   *a.cap = newcap
   *a.ptr = newptr
}
newlen = len + 3
*a.len = newlen
*(ptr+len) = 1
*(ptr+len+1) = 2
*(ptr+len+2) = 3
是否覆盖原变量的逻辑其实差不多，最大的区别在于得到的新切片是否会赋值回原变量。如果我们选择覆盖原有的变量，就不需要担心切片发生拷贝影响性能，因为Go语言编译器已经对这种常见的情况做出了优化。

Go语言的切片追加元素
到这里我们已经清楚了Go语言如何在切片容量足够时向切片中追加元素，不过仍然需要研究切片容量不足时的处理流程。当切片的容量不足时，我们会调用runtime.growslice函数为切片扩容，扩容是为切片分配新的内存空间并拷贝原切片中元素的过程，我们先来看新切片的容量是如何确定的：
func growslice(et *_type, old slice, cap int) slice {
	newcap := old.cap
	doublecap := newcap + newcap
	if cap &gt; doublecap {
		newcap = cap
	} else {
		if old.len &lt; 1024 {
			newcap = doublecap
		} else {
			for 0 &lt; newcap &amp;&amp; newcap &lt; cap {
				newcap += newcap / 4
			}
			if newcap &lt;= 0 {
				newcap = cap
			}
		}
    }
}
在分配内存空间之前需要先确定新的切片容量，运行时根据切片的当前容量选择不同的策略进行扩容：

如果期望容量大于当前容量的两倍就会使用期望容量；
如果当前切片的长度小于 1024 就会将容量翻倍；
如果当前切片的长度大于 1024 就会每次增加 25% 的容量，直到新容量大于期望容量；

上述代码片段仅会确定切片的大致容量，下面还需要根据切片中的元素大小对齐内存，当数组中元素所占的字节大小为 1、8 或者 2 的倍数时，运行时会使用如下所示的代码对齐内存：
var overflow bool
	var lenmem, newlenmem, capmem uintptr
	switch {
	case et.size == 1:
		lenmem = uintptr(old.len)
		newlenmem = uintptr(cap)
		capmem = roundupsize(uintptr(newcap))
		overflow = uintptr(newcap) &gt; maxAlloc
		newcap = int(capmem)
	case et.size == sys.PtrSize:
		lenmem = uintptr(old.len) * sys.PtrSize
		newlenmem = uintptr(cap) * sys.PtrSize
		capmem = roundupsize(uintptr(newcap) * sys.PtrSize)
		overflow = uintptr(newcap) &gt; maxAlloc/sys.PtrSize
		newcap = int(capmem / sys.PtrSize)
	case isPowerOfTwo(et.size):
		...
	default:
		...
	}
runtime.roundupsize函数会将待申请的内存向上取整，取整时会使用runtime.class_to_size数组，使用该数组中的整数可以提高内存的分配效率并减少碎片，我们会在内存分配一节详细介绍该数组的作用：
var class_to_size = [_NumSizeClasses]uint16{
    0,
    8,
    16,
    32,
    48,
    64,
    80,
    ...,
}
在默认情况下，我们会将目标容量和元素大小相乘得到占用的内存。如果计算新容量时发生了内存溢出或者请求内存超过上限，就会直接崩溃退出程序，不过这里为了减少理解的成本，将相关的代码省略了。
var overflow bool
	var newlenmem, capmem uintptr
	switch {
	...
	default:
		lenmem = uintptr(old.len) * et.size
		newlenmem = uintptr(cap) * et.size
		capmem, _ = math.MulUintptr(et.size, uintptr(newcap))
		capmem = roundupsize(capmem)
		newcap = int(capmem / et.size)
	}
	...
	var p unsafe.Pointer
	if et.kind&amp;kindNoPointers != 0 {
		p = mallocgc(capmem, nil, false)
		memclrNoHeapPointers(add(p, newlenmem), capmem-newlenmem)
	} else {
		p = mallocgc(capmem, et, true)
		if writeBarrier.enabled {
			bulkBarrierPreWriteSrcOnly(uintptr(p), uintptr(old.array), lenmem)
		}
	}
	memmove(p, old.array, lenmem)
	return slice{p, old.len, newcap}
如果切片中的元素不是指针类型，那么会调用runtime.memclrNoHeapPointers将超出切片当前长度的位置清空并在最后使用runtime.memmove将原数组内存中的内容拷贝到新申请的内存中。
runtime.growslice函数最终会返回一个新的切片，其中包含了新的数组指针、大小和容量，这个返回的三元组最终会覆盖原切片
var arr []int64
arr = append(arr, 1, 2, 3, 4, 5)
简单总结一下扩容的过程，当我们执行上述代码时，会触发runtime.growslice函数扩容arr切片并传入期望的新容量5，这时期望分配的内存大小为40字节；不过因为切片中的元素大小等于sys.PtrSize，所以运行时会调用runtime.roundupsize向上取整内存的大小到48字节，所以心切片的容量为48/8=6。
拷贝切片
切片的拷贝虽然不是常见的操作，但是确实我们学习切片实现原理必须要涉及的。当我们使用copy(a, b)的形式对切片进行拷贝时，编译期间的cmd/compile/internal/gc.copyany也会分两种情况进行处理拷贝操作，如果当前copy不是在运行时调用的，copy(a, b)会被直接转换成下面的代码：
n := len(a)
if n &gt; len(b) {
    n = len(b)
}
if a.ptr != b.ptr {
    memmove(a.ptr, b.ptr, n*sizeof(elem(a)))
}
上述代码中的runtime.memmove会负责拷贝内存。而如果拷贝是在运行时发生的，例如go copy(a, b)，编译器会使用runtime.slicecopy替换运行期间调用的copy，该函数的实现很简单：
func slicecopy(to, fm slice, width uintptr) int {
	if fm.len == 0 || to.len == 0 {
		return 0
	}
	n := fm.len
	if to.len &lt; n {
		n = to.len
	}
	if width == 0 {
		return n
	}
	...

	size := uintptr(n) * width
	if size == 1 {
		*(*byte)(to.array) = *(*byte)(fm.array)
	} else {
		memmove(to.array, fm.array, size)
	}
	return n
}
无论是编译期间拷贝还是运行时拷贝，两种拷贝方式都会通过runtime.memmove将整块内存的内容拷贝到目标的内存区域中：

Go语言切片的拷贝
相比于依次拷贝元素，runtime.memmove能够提供更好的性能。需要注意的是，整块拷贝内存仍然会占用非常多的资源，在大切片上执行拷贝操作时一定要注意对性能的影响
小结
切片的很多功能都是由运行时实现的，无论是初始化切片，还是对切片进行追加或扩容都需要运行时的支持，需要注意的是在遇到大切片扩容或者复制时可能会发生大规模的内存拷贝，一定要减少类似操作避免影响程序的性能

golang/进阶/go-实战-—-结构体验证器-validator.content:
Go 实战 — validator参数校验

原文：xyf1111.github.io/go-study18/

在web开发中一个不可避免的环节就是对请求参数进行校验，通常我们对在代码中定义和请求参数相对应的模型(结构体)，借助模型绑定快捷地解析请求中的参数，例如gin框架中的Bind和ShouldBind系列的方法。本文就以gin框架的请求参数校验为例，介绍一些validator库的实用技巧。
gin框架使用的是github.com/go-playground/validator进行参数校验，目前已经支持github.com/go-playground/validator/v10了，我们需要在定义结构体时使用binding tag标识相关校验规则。
基本示例
首先来看gin框架内置使用validator做参数校验的基本示例。
package main

import (
    &quot;net/http&quot;

    &quot;github.com/gin-gonic/gin&quot;
)

type SignUpParam struct {
    Age         uint8   `json:&quot;age&quot; binding:&quot;gte=1, lte=130&quot;`
    Name        string  `json:&quot;name&quot; binding:&quot;required&quot;`
    Email       string  `json:&quot;email&quot; binding:&quot;required, email&quot;`
    Password    string  `json:&quot;password&quot; binding:&quot;required&quot;`
    RePassword  string  `josn:&quot;re_password&quot; binding:&quot;required, eqfield=Password&quot;`
}

func main() {
    r := gin.Default()

    r.POST(&quot;/signup&quot;, func(c *gin.Context) {
        var u SignUpParam
        if err := c.ShouldBind(&amp;u), err != nil {
            c.JSON(http/StatusOK, gin.H{
                &quot;msg&quot;:  err.Error(),
            })
            return
        }
        // 保存入库等业务逻辑代码...

        c.JSON(http.StatusOK, &quot;success&quot;)
    })

    _ := r.Run(&quot;:8999&quot;)
}
我们使用curl发送一个POST请求测试下
curl -H &quot;Content-type: application/json&quot; -X POST -d &#039;{&quot;name&quot;: &quot;q1mi&quot;, &quot;age&quot;: 18, &quot;email&quot;: &quot;123.com&quot;}&#039; http://127.0.0.1:8999/signup
输出结果
{&quot;msg&quot;:&quot;Key: &#039;SignUpParam.Email&#039; Error:Field validation for &#039;Email&#039; failed on the &#039;email&#039; tag\nKey: &#039;SignUpParam.Password&#039; Error:Field validation for &#039;Password&#039; failed on the &#039;required&#039; tag\nKey: &#039;SignUpParam.RePassword&#039; Error:Field validation for &#039;RePassword&#039; failed on the &#039;required&#039; tag&quot;}
从最终的输出结果可以看到validator的检验生效了，但是错误提示的字段不是特别友好，我们可能需要将它翻译成中文
翻译校验错误提示信息
validator库本身是支持国际化的，借助相应的语言包可以实现校验错误提示信息的自动翻译。下面的示例代码演示了如何将错误提示信息翻译成中文，翻译成其他语言的方法类似。
package  main
import (
    &quot;fmt&quot;
    &quot;net/http&quot;

    &quot;github.com/gin-gonic/gin&quot;
    &quot;github.com/gin-gonic/gin/binding&quot;
    &quot;github.com/go-playground/locales/en&quot;
    &quot;github.com/go-playground/locales/zh&quot;
    ut &quot;github.com/go-playground/universal-translator&quot;
    &quot;github.com/go-playground/validator/v10&quot;
    enTranslations &quot;github.com/go-playground/validator/v10/translations/en&quot;
    zhTranslations &quot;github.com/go-playground/validator/v10/translations/zh&quot;
)

// 定义一个全局翻译器T
var trans ut.Translator

// InitTrans 初始化翻译器
func InitTrans(locale string) (err error) {
    if v, ok := binding.Validator.Engine().(*validator.Validate); ok {
        // 中文翻译器
        zhT := zh.New()
        // 英文翻译器
        enT := en.New()

        // 第一个参数是备用(fallback)的语言环境
        // 后面的参数是应该支持的语言环境(支持多个)
        // uni := ut.New(zhT, zhT)也是可以的
        uni := ut.New(enT, zhT, enT)

        // locale通常取决于http请求头的&#039;Accept-Language&#039;
        var ok bool
        // 也可以使用uni.FindTranslator(...)传入多个locale进行查找
        trans, ok = uni.GetTranslator(locale)
        if !ok {
            return fmt.Errorf(&quot;uni.GetTranslator(%s) failed&quot;, locale)
        }

        // 注册翻译器
        switch locale {
            case &quot;en&quot;:
                err = enTranslations.RegisterDefaultTranslations(v, trans)
            case &quot;zh&quot;:
                err = zhTranslations.RegisterDefaultTranslations(v, trans)
            default:
                err = enTranslations.RegisterDefaultTranslations(v, trans)
        }
        return
    }
    return
}

type SignUpParam struct {
    Age         uint8   `json:&quot;age&quot; binding:&quot;gte=1,lte=130&quot;`
    Name        string  `json:&quot;name&quot; binding:&quot;required&quot;`
    Email       string  `json:&quot;email&quot; binding:&quot;required,email&quot;`
    Password    string  `json:&quot;password&quot; binding:&quot;required&quot;`
    RePassword  string  `json:&quot;re_password&quot; binding:&quot;required,eqfield=Password&quot;`
}

func main() {
    if err := InitTrans(&quot;zh&quot;); err != nil {
        fmt.Printf(&quot;init trans failed, err:%v\n&quot;, err)
        return
    }

    r := gin.Default()

    r.POST(&quot;/signup&quot;, func(c *gin.Context) {
        var u SignUpParam
        if err := c.ShouldBind(&amp;u); err != nil {
            // 获取validator.ValidationErrors类型的errors
            errs, ok := err.(validator.ValidationErrors)
            if !ok {
                // 非validator.ValidationErrors类型错误直接返回
                c.JSON(http.StatusOK, gin.H{
                    &quot;msg&quot;: err.Error(),
                })
                return
            }
            // validator.ValidationErrors类型错误则进行翻译
            c.JSON(http.Status, gin.H{
                &quot;msg&quot;: errs.Translate(trans),
            })
            return
        }
        // 保存入库等具体业务逻辑代码...

        c.JSON(http.StatusOK, &quot;success&quot;)
    })
    _ = r.Run(&quot;:8999&quot;)
}
我们使用curl发送一个POST请求测试下：
curl -H &quot;Content-type: application/json&quot; -X POST -d &#039;{&quot;name&quot;:&quot;q1mi&quot;, &quot;age&quot;:18, &quot;email&quot;:&quot;123.com&quot;}&#039; http://127.0.0.1:8999/signup
输出结果：
{&quot;msg&quot;: &quot;Key: &#039;SignUpParam.Email&#039; Error:Field validation for &#039;Email&#039; failed on the &#039;email&#039; tag\nKey: &#039;SignUpParam.Password&#039; Error:Field validation for &#039;Password&#039; failed on the &#039;required&#039; tag\nKey: &#039;SignUpParam.RePassword&#039; Error:Field validation for &#039;RePassword&#039; failed on the &#039;required&#039; tag&quot;}
从最终的输出结果可以看到validator的检验生效了，但是错误提示的字段不是很友好，我们可能需要将它翻译成中文
翻译校验错误提示信息
validator库本身是支持国际化的，借助相应的语言包可以实现校验错误提示信息的自动翻译，下面的示例代码演示了如何将错误提示信息翻译成中文，翻译成其他语言的方法类似
package main

import (
    &quot;fmt&quot;
    &quot;net/http&quot;

    &quot;github.com/gin-gonic/gin&quot;
	&quot;github.com/gin-gonic/gin/binding&quot;
	&quot;github.com/go-playground/locales/en&quot;
	&quot;github.com/go-playground/locales/zh&quot;
	ut &quot;github.com/go-playground/universal-translator&quot;
	&quot;github.com/go-playground/validator/v10&quot;
	enTranslations &quot;github.com/go-playground/validator/v10/translations/en&quot;
	zhTranslations &quot;github.com/go-playground/validator/v10/translations/zh&quot;
)

// 定义一个全局翻译器T
var trans ut.Translator

// 初始化翻译器
func InitTrans(locale string) (err error) {
    // 修改gin框架中的Validator引擎属性，实现自定制
    if v, ok := binding.Validator.Engine().(*validator.Validate); ok {

        zhT := zh.New() // 中文翻译器
		enT := en.New() // 英文翻译器

		// 第一个参数是备用（fallback）的语言环境
		// 后面的参数是应该支持的语言环境（支持多个）
		// uni := ut.New(zhT, zhT) 也是可以的
		uni := ut.New(enT, zhT, enT)

		// locale 通常取决于 http 请求头的 &#039;Accept-Language&#039;
		var ok bool
		// 也可以使用 uni.FindTranslator(...) 传入多个locale进行查找
		trans, ok = uni.GetTranslator(locale)
		if !ok {
			return fmt.Errorf(&quot;uni.GetTranslator(%s) failed&quot;, locale)
		}

		// 注册翻译器
		switch locale {
		case &quot;en&quot;:
			err = enTranslations.RegisterDefaultTranslations(v, trans)
		case &quot;zh&quot;:
			err = zhTranslations.RegisterDefaultTranslations(v, trans)
		default:
			err = enTranslations.RegisterDefaultTranslations(v, trans)
		}
		return
    }
    return
}

type SignUpParam struct {
	Age        uint8  `json:&quot;age&quot; binding:&quot;gte=1,lte=130&quot;`
	Name       string `json:&quot;name&quot; binding:&quot;required&quot;`
	Email      string `json:&quot;email&quot; binding:&quot;required,email&quot;`
	Password   string `json:&quot;password&quot; binding:&quot;required&quot;`
	RePassword string `json:&quot;re_password&quot; binding:&quot;required,eqfield=Password&quot;`
}

func main() {
	if err := InitTrans(&quot;zh&quot;); err != nil {
		fmt.Printf(&quot;init trans failed, err:%v\n&quot;, err)
		return
	}

	r := gin.Default()

	r.POST(&quot;/signup&quot;, func(c *gin.Context) {
		var u SignUpParam
		if err := c.ShouldBind(&amp;u); err != nil {
			// 获取validator.ValidationErrors类型的errors
			errs, ok := err.(validator.ValidationErrors)
			if !ok {
				// 非validator.ValidationErrors类型错误直接返回
				c.JSON(http.StatusOK, gin.H{
					&quot;msg&quot;: err.Error(),
				})
				return
			}
			// validator.ValidationErrors类型错误则进行翻译
			c.JSON(http.StatusOK, gin.H{
				&quot;msg&quot;:errs.Translate(trans),
			})
			return
		}
		// 保存入库等具体业务逻辑代码...

		c.JSON(http.StatusOK, &quot;success&quot;)
	})

	_ = r.Run(&quot;:8999&quot;)
}
同样的请求再来一次
curl -H &quot;Content-type: application/json&quot; -X POST -d &#039;{&quot;name&quot;:&quot;q1mi&quot;,&quot;age&quot;:18,&quot;email&quot;:&quot;123.com&quot;}&#039; http://127.0.0.1:8999/signup
这次的输出结果如下
{&quot;msg&quot;:{&quot;SignUpParam.Email&quot;:&quot;Email必须是一个有效的邮箱&quot;,&quot;SignUpParam.Password&quot;:&quot;Password为必填字段&quot;,&quot;SignUpParam.RePassword&quot;:&quot;RePassword为必填字段&quot;}}
自定义错误提示信息的字段名
上面的错误提示看起来可以了，但是还是差点意思，首先是错误提示中的字段并不是请求中使用的字段，例如：RePassword使我们后端定义的结构体中的字段名，而请求中使用的是re_password字段。如何使错误提示中的字段使用自定义的名称，例如json tag指定的值？
只需要在初始化翻译器的时候像下面一样添加一个获取json tag的自定义方法即可。
// InitTrans 初始化翻译器
func InitTrans(locale string) (err error) {
	// 修改gin框架中的Validator引擎属性，实现自定制
	if v, ok := binding.Validator.Engine().(*validator.Validate); ok {

		// 注册一个获取json tag的自定义方法
		v.RegisterTagNameFunc(func(fld reflect.StructField) string {
			name := strings.SplitN(fld.Tag.Get(&quot;json&quot;), &quot;,&quot;, 2)[0]
			if name == &quot;-&quot; {
				return &quot;&quot;
			}
			return name
		})

		zhT := zh.New() // 中文翻译器
		enT := en.New() // 英文翻译器

		// 第一个参数是备用（fallback）的语言环境
		// 后面的参数是应该支持的语言环境（支持多个）
		// uni := ut.New(zhT, zhT) 也是可以的
		uni := ut.New(enT, zhT, enT)

		// ... liwenzhou.com ...
}
再尝试发请求，看一下效果：
{&quot;msg&quot;:{&quot;SignUpParam.email&quot;:&quot;email必须是一个有效的邮箱&quot;,&quot;SignUpParam.password&quot;:&quot;password为必填字段&quot;,&quot;SignUpParam.re_password&quot;:&quot;re_password为必填字段&quot;}}
可以看到现在错误提示信息中使用的就是我们结构体中json tag设置的名称了
但是还是有点瑕疵，那就是最终的错误提示信息中心还是有我们后端定义的结构体名称–SignUpParam，这个名称其实是不需要随错误提示返回给前端的，前端并不需要这个值。我们需要想办法把它去掉。
这里参考github.com/go-playground/validator/issues/633#issuecomment-654382345提供的方法，定义一个去掉结构体名称前缀的自定义方法：
func removeTopStruct(fields map[string]string) map[string]string {
	res := map[string]string{}
	for field, err := range fields {
		res[field[strings.Index(field, &quot;.&quot;)+1:]] = err
	}
	return res
}
我们在代码中使用上述函数将翻译后的errors做一下处理即可：
if err := c.ShouldBind(&amp;u); err != nil {
	// 获取validator.ValidationErrors类型的errors
	errs, ok := err.(validator.ValidationErrors)
	if !ok {
		// 非validator.ValidationErrors类型错误直接返回
		c.JSON(http.StatusOK, gin.H{
			&quot;msg&quot;: err.Error(),
		})
		return
	}
	// validator.ValidationErrors类型错误则进行翻译
	// 并使用removeTopStruct函数去除字段名中的结构体名称标识
	c.JSON(http.StatusOK, gin.H{
		&quot;msg&quot;: removeTopStruct(errs.Translate(trans)),
	})
	return
}
看一下最终的效果
{&quot;msg&quot;:{&quot;email&quot;:&quot;email必须是一个有效的邮箱&quot;,&quot;password&quot;:&quot;password为必填字段&quot;,&quot;re_password&quot;:&quot;re_password为必填字段&quot;}}
这一次看起来就比较符合我们预期的标准了。
自定义结构体校验方法
上面的校验还是有点小问题，就是当涉及到一些复杂的校验规则，比如re_password字段需要与password字段的值相等这样的校验规则，我们的自定义错误提示字段名称方法就不能很好解决错误提示信息中的其他字段名称了。
curl -H &quot;Content-type: application/json&quot; -X POST -d &#039;{&quot;name&quot;:&quot;q1mi&quot;,&quot;age&quot;:18,&quot;email&quot;:&quot;123.com&quot;,&quot;password&quot;:&quot;123&quot;,&quot;re_password&quot;:&quot;321&quot;}&#039; http://127.0.0.1:8999/signup
最后输出的错误提示信息如下
{&quot;msg&quot;:{&quot;email&quot;:&quot;email必须是一个有效的邮箱&quot;,&quot;re_password&quot;:&quot;re_password必须等于Password&quot;}}
可以看到re_password字段的提示信息中还是出现了Password这个结构体字段名称。这有点小小的遗憾，毕竟自定义字段名称的方法不能影响被当成param传入的值。
此时如果想要追求更好的提示效果，将上面的Password字段也改为和json tag一致的名称，就需要我们自定义结构体校验的方法。
例如，我们为SignUpParam自定义一个校验方法如下：
// SignUpParamStructLevelValidation 自定义SignUpParam结构体校验函数
func SignUpParamStructLevelValidation(sl validator.StructLevel) {
	su := sl.Current().Interface().(SignUpParam)

	if su.Password != su.RePassword {
		// 输出错误提示信息，最后一个参数就是传递的param
		sl.ReportError(su.RePassword, &quot;re_password&quot;, &quot;RePassword&quot;, &quot;eqfield&quot;, &quot;password&quot;)
	}
}
然后在初始化校验器的函数中注册该自定义校验方法即可：
func InitTrans(locale string) (err error) {
	// 修改gin框架中的Validator引擎属性，实现自定制
	if v, ok := binding.Validator.Engine().(*validator.Validate); ok {

		// ... liwenzhou.com ...

		// 为SignUpParam注册自定义校验方法
		v.RegisterStructValidation(SignUpParamStructLevelValidation, SignUpParam{})

		zhT := zh.New() // 中文翻译器
		enT := en.New() // 英文翻译器

		// ... liwenzhou.com ...
}
最终再请求一次，看一下效果：
{&quot;msg&quot;:{&quot;email&quot;:&quot;email必须是一个有效的邮箱&quot;,&quot;re_password&quot;:&quot;re_password必须等于password&quot;}}
这一次re_password字段的错误提示信息就符合我们预期了。
自定义字段校验方法
除了上面介绍到的自定义结构体校验方法，validator还支持为某个字段自定义校验方法，并使用RegisterValidation()注册到校验器实例中。
接下来我们来为SignUpParam添加一个需要使用自定义校验方法checkDate做参数校验的字段Date。
type SignUpParam struct {
	Age        uint8  `json:&quot;age&quot; binding:&quot;gte=1,lte=130&quot;`
	Name       string `json:&quot;name&quot; binding:&quot;required&quot;`
	Email      string `json:&quot;email&quot; binding:&quot;required,email&quot;`
	Password   string `json:&quot;password&quot; binding:&quot;required&quot;`
	RePassword string `json:&quot;re_password&quot; binding:&quot;required,eqfield=Password&quot;`
	// 需要使用自定义校验方法checkDate做参数校验的字段Date
	Date       string `json:&quot;date&quot; binding:&quot;required,datetime=2006-01-02,checkDate&quot;`
}
其中datetime=2006-01-02是内置的用于校验日期类参数是否满足指定格式要求的tag。 如果传入的date参数不满足2006-01-02这种格式就会提示如下错误：
{&quot;msg&quot;:{&quot;date&quot;:&quot;date的格式必须是2006-01-02&quot;}}
针对date字段除了内置的datetime=2006-01-02提供的格式要求外，假设我们还要求该字段的时间必须是一个未来的时间（晚于当前时间），像这样针对某个字段的特殊校验需求就需要我们使用自定义字段校验方法了。
首先我们要在需要执行自定义校验的字段后面添加自定义tag，这里使用的是checkDate，注意使用英文分号分隔开。
// customFunc 自定义字段级别校验方法
func customFunc(fl validator.FieldLevel) bool {
	date, err := time.Parse(&quot;2006-01-02&quot;, fl.Field().String())
	if err != nil {
		return false
	}
	if date.Before(time.Now()) {
		return false
	}
	return true
}
定义好了字段及其自定义校验方法后，就需要将它们联系起来并注册到我们的校验器实例中。
// 在校验器注册自定义的校验方法
if err := v.RegisterValidation(&quot;checkDate&quot;, customFunc); err != nil {
	return err
}
这样，我们就可以对请求参数中date字段执行自定义的checkDate进行校验了。 我们发送如下请求测试一下：
curl -H &quot;Content-type: application/json&quot; -X POST -d &#039;{&quot;name&quot;:&quot;q1mi&quot;,&quot;age&quot;:18,&quot;email&quot;:&quot;123@qq.com&quot;,&quot;password&quot;:&quot;123&quot;, &quot;re_password&quot;: &quot;123&quot;, &quot;date&quot;:&quot;2020-01-02&quot;}&#039; http://127.0.0.1:8999/signup
此时得到的响应结果是：
{&quot;msg&quot;:{&quot;date&quot;:&quot;Key: &#039;SignUpParam.date&#039; Error:Field validation for &#039;date&#039; failed on the &#039;checkDate&#039; tag&quot;}}
这…自定义字段级别的校验方法的错误提示信息很“简单粗暴”，和我们上面的中文提示风格有出入，必须想办法搞定它呀！
自定义翻译方法
我们现在需要为自定义字段校验方法提供一个自定义的翻译方法，从而实现该字段错误提示信息的自定义显示。
// registerTranslator 为自定义字段添加翻译功能
func registerTranslator(tag string, msg string) validator.RegisterTranslationsFunc {
	return func(trans ut.Translator) error {
		if err := trans.Add(tag, msg, false); err != nil {
			return err
		}
		return nil
	}
}

// translate 自定义字段的翻译方法
func translate(trans ut.Translator, fe validator.FieldError) string {
	msg, err := trans.T(fe.Tag(), fe.Field())
	if err != nil {
		panic(fe.(error).Error())
	}
	return msg
}
定义好了相关翻译方法之后，我们在InitTrans函数中通过调用RegisterTranslation()方法来注册我们自定义的翻译方法。
// InitTrans 初始化翻译器
func InitTrans(locale string) (err error) {
	// ...liwenzhou.com...

		// 注册翻译器
		switch locale {
		case &quot;en&quot;:
			err = enTranslations.RegisterDefaultTranslations(v, trans)
		case &quot;zh&quot;:
			err = zhTranslations.RegisterDefaultTranslations(v, trans)
		default:
			err = enTranslations.RegisterDefaultTranslations(v, trans)
		}
		if err != nil {
			return err
		}
		// 注意！因为这里会使用到trans实例
		// 所以这一步注册要放到trans初始化的后面
		if err := v.RegisterTranslation(
			&quot;checkDate&quot;,
			trans,
			registerTranslator(&quot;checkDate&quot;, &quot;{0}必须要晚于当前日期&quot;),
			translate,
		); err != nil {
			return err
		}
		return
	}
	return
}
这样再次尝试发送请求，就能得到想要的错误提示信息了。
{&quot;msg&quot;:{&quot;date&quot;:&quot;date必须要晚于当前日期&quot;}}
总结
本文总结的gin框架中validator的使用技巧同样也适用于直接使用validator库，区别仅仅在于我们配置的是gin框架中的校验器还是由validator.New()创建的校验器。同时使用validator库确实能够在一定程度上减少我们的编码量，但是它不太可能完美解决我们所有需求，所以你需要找到两者之间的平衡点。

